import { create } from 'zustand';
import { devtools } from 'zustand/middleware';
import type {
  HorizonItem,
  Zone,
  Complexity,
  Model,
  Plan,
} from '@/types';

// ============================================================================
// Types
// ============================================================================

interface HorizonState {
  // Data
  items: HorizonItem[];
  selectedItemId: string | null;
  isLoading: boolean;
  error: string | null;

  // Actions
  setItems: (items: HorizonItem[]) => void;
  addItem: (title: string, zone: Zone, repo: string) => void;
  updateItem: (id: string, updates: Partial<HorizonItem>) => void;
  deleteItem: (id: string) => void;
  promoteItem: (id: string, targetZone: Zone) => void;
  dispatchItem: (id: string) => Promise<void>;
  approvePlan: (id: string) => Promise<void>;
  requestReplan: (id: string, constraint: string) => Promise<void>;
  updateTaskModel: (itemId: string, taskId: string, model: Model) => void;
  updateTaskComplexity: (itemId: string, taskId: string, complexity: Complexity) => void;
  reorderItems: (zone: Zone, fromIndex: number, toIndex: number) => void;
  setSelectedItem: (id: string | null) => void;
  setLoading: (loading: boolean) => void;
  setError: (error: string | null) => void;

  // Selectors
  getItemsByZone: (zone: Zone) => HorizonItem[];
  getItemById: (id: string) => HorizonItem | undefined;
}

// ============================================================================
// Store
// ============================================================================

export const useHorizonStore = create<HorizonState>()(
  devtools(
    (set, get) => ({
      // Initial state
      items: [],
      selectedItemId: null,
      isLoading: false,
      error: null,

      // Actions
      setItems: (items) => set({ items }),

      addItem: (title, zone, repo) => {
        const newItem: HorizonItem = {
          id: `item-${Date.now()}`,
          title,
          zone,
          repo,
          complexity: null,
          priority: 0,
          plan: null,
          linearTicketId: null,
          createdAt: new Date(),
          updatedAt: new Date(),
          conflictingFiles: [],
        };

        set((state) => ({
          items: [...state.items, newItem],
        }));
      },

      updateItem: (id, updates) =>
        set((state) => ({
          items: state.items.map((item) =>
            item.id === id
              ? { ...item, ...updates, updatedAt: new Date() }
              : item
          ),
        })),

      deleteItem: (id) =>
        set((state) => ({
          items: state.items.filter((item) => item.id !== id),
          selectedItemId:
            state.selectedItemId === id ? null : state.selectedItemId,
        })),

      promoteItem: (id, targetZone) => {
        set((state) => ({
          items: state.items.map((item) =>
            item.id === id
              ? { ...item, zone: targetZone, updatedAt: new Date() }
              : item
          ),
        }));

        // If promoting to REFINING, trigger plan generation
        if (targetZone === 'REFINING') {
          // TODO: Call API to generate plan
          console.log('Plan generation triggered for item:', id);
        }
      },

      dispatchItem: async (id) => {
        set({ isLoading: true, error: null });
        try {
          // TODO: Call dispatch API
          // const response = await fetch(`/api/fleet/dispatch/${id}`, { method: 'POST' });

          // Remove from horizon (it's now in the fleet)
          set((state) => ({
            items: state.items.filter((item) => item.id !== id),
            isLoading: false,
          }));
        } catch (error) {
          set({
            error: error instanceof Error ? error.message : 'Failed to dispatch',
            isLoading: false,
          });
        }
      },

      approvePlan: async (id) => {
        set({ isLoading: true, error: null });
        try {
          // TODO: Call approve API

          // Move to READY
          set((state) => ({
            items: state.items.map((item) =>
              item.id === id
                ? { ...item, zone: 'READY' as Zone, updatedAt: new Date() }
                : item
            ),
            isLoading: false,
          }));
        } catch (error) {
          set({
            error: error instanceof Error ? error.message : 'Failed to approve plan',
            isLoading: false,
          });
        }
      },

      requestReplan: async (id, constraint) => {
        set({ isLoading: true, error: null });
        try {
          // TODO: Call replan API with constraint
          console.log('Replanning with constraint:', constraint);

          set({ isLoading: false });
        } catch (error) {
          set({
            error: error instanceof Error ? error.message : 'Failed to replan',
            isLoading: false,
          });
        }
      },

      updateTaskModel: (itemId, taskId, model) =>
        set((state) => ({
          items: state.items.map((item) => {
            if (item.id !== itemId || !item.plan) return item;

            const updateTasks = (tasks: typeof item.plan.workstreams[0]['tasks']) =>
              tasks.map((task) =>
                task.id === taskId ? { ...task, modelOverride: model } : task
              );

            return {
              ...item,
              plan: {
                ...item.plan,
                workstreams: item.plan.workstreams.map((ws) => ({
                  ...ws,
                  tasks: updateTasks(ws.tasks),
                })),
                sequentialTasks: updateTasks(item.plan.sequentialTasks),
              },
              updatedAt: new Date(),
            };
          }),
        })),

      updateTaskComplexity: (itemId, taskId, complexity) =>
        set((state) => ({
          items: state.items.map((item) => {
            if (item.id !== itemId || !item.plan) return item;

            const updateTasks = (tasks: typeof item.plan.workstreams[0]['tasks']) =>
              tasks.map((task) =>
                task.id === taskId ? { ...task, complexity } : task
              );

            return {
              ...item,
              plan: {
                ...item.plan,
                workstreams: item.plan.workstreams.map((ws) => ({
                  ...ws,
                  tasks: updateTasks(ws.tasks),
                })),
                sequentialTasks: updateTasks(item.plan.sequentialTasks),
              },
              updatedAt: new Date(),
            };
          }),
        })),

      reorderItems: (zone, fromIndex, toIndex) =>
        set((state) => {
          const zoneItems = state.items.filter((item) => item.zone === zone);
          const [movedItem] = zoneItems.splice(fromIndex, 1);
          zoneItems.splice(toIndex, 0, movedItem);

          // Update priorities
          const updatedZoneItems = zoneItems.map((item, index) => ({
            ...item,
            priority: index,
          }));

          // Merge back with other zones
          const otherItems = state.items.filter((item) => item.zone !== zone);

          return {
            items: [...otherItems, ...updatedZoneItems],
          };
        }),

      setSelectedItem: (id) => set({ selectedItemId: id }),

      setLoading: (isLoading) => set({ isLoading }),

      setError: (error) => set({ error }),

      // Selectors
      getItemsByZone: (zone) => get().items.filter((item) => item.zone === zone),

      getItemById: (id) => get().items.find((item) => item.id === id),
    }),
    { name: 'horizon-store' }
  )
);
